previewCss:
.darma-loader-darma-custom-379 {color: var(--loader-color, #0284c7);
  --loader-secondary-color: var(--loader-secondary-color, #7dd3fc);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 64px;
  aspect-ratio: 1;
  display: grid;
}.darma-loader-darma-custom-379:before,.darma-loader-darma-custom-379:after {content: "";
  grid-area: 1/1;
  border: 8px solid var(--loader-color, #0284c7);
  box-sizing: content-box;
  margin: auto;
  aspect-ratio: 1;
  animation: darma-loader-darma-custom-379-l8 infinite 1s steps(4,jump-none);
}.darma-loader-darma-custom-379:before {animation-delay: -.5s;
  border-radius: 50%;
}@keyframes darma-loader-darma-custom-379-l8 {0% {width: 0% }to {width: 75%}}

